/**
 * Result from discovering a synced passkey during restore
 */
data class DiscoveredPasskeyResult (
    /**
     * 32-byte PRF key
     */
    var `prfOutput`: kotlin.ByteArray
    , 
    /**
     * Discovered credential ID, persisted to local keychain
     */
    var `credentialId`: kotlin.ByteArray
    
){
    

    

    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeDiscoveredPasskeyResult: FfiConverterRustBuffer<DiscoveredPasskeyResult> {
    override fun read(buf: ByteBuffer): DiscoveredPasskeyResult {
        return DiscoveredPasskeyResult(
            FfiConverterByteArray.read(buf),
            FfiConverterByteArray.read(buf),
        )
    }

    override fun allocationSize(value: DiscoveredPasskeyResult) = (
            FfiConverterByteArray.allocationSize(value.`prfOutput`) +
            FfiConverterByteArray.allocationSize(value.`credentialId`)
    )

    override fun write(value: DiscoveredPasskeyResult, buf: ByteBuffer) {
            FfiConverterByteArray.write(value.`prfOutput`, buf)
            FfiConverterByteArray.write(value.`credentialId`, buf)
    }
}





sealed class CloudStorageException: kotlin.Exception() {
    
    class NotAvailable(
        
        val v1: kotlin.String
        ) : CloudStorageException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class Offline(
        
        val v1: kotlin.String
